args.sparql:
SELECT ?book ?title WHERE {
  ?book wdt:P195 wd:Q5374214.
  ?book wdt:P1476 ?title.
  FILTER (LANG(?title) = "en")
}

SELECT ?title WHERE {
  ?book wdt:P155 wd:Q5374214;
        wdt:P1476 ?title;
        wdt:P1545 ?ordinal.
  FILTER (LANG(?title) = "en").
}
ORDER BY ?ordinal
LIMIT 1 OFFSET 2
